transform_js:
const colors = ['#FF6B6B', '#FF8E53', '#FFA03A', '#FFB732', '#FFCE54'];
const maxVal = rawData.rows[0].value;
const chartData = rawData.rows.map((r, i) => {
  return {
    name: r.step,
    value: r.value,
    pct: (r.value / maxVal * 100).toFixed(1) + '%',
    color: colors[i % colors.length]
  };
});
const barData = chartData.map(d => ({
  name: d.name,
  value: d.value,
  itemStyle: { color: d.color }
}));
const circleData = chartData.map((d, i) => ({
  name: d.name,
  value: [0, i],
  pct: d.pct,
  itemStyle: { color: d.color }
}));
transformedData = { barData, circleData, categories: chartData.map(d => d.name), colors };

echarts_js:
option = {
  backgroundColor: '#fdfdfd',
  tooltip: {
    trigger: 'axis',
    axisPointer: { type: 'shadow' },
    formatter: function (params) {
      if (!params[0]) return '';
      return params[0].name + ': ' + params[0].value.toLocaleString() + '件';
    }
  },
  grid: [
    { left: '32%', right: '15%', top: 50, bottom: 30, containLabel: false },
    { left: '5%', width: '10%', top: 50, bottom: 30, containLabel: false }
  ],
  xAxis: [
    { type: 'value', show: false, gridIndex: 0 },
    { type: 'value', show: false, min: 0, max: 1, gridIndex: 1 }
  ],
  yAxis: [
    {
      type: 'category',
      data: transformedData.categories,
      inverse: true,
      axisLine: { show: false },
      axisTick: { show: false },
      axisLabel: { show: true, fontSize: 14, fontWeight: 'bold', color: '#444', margin: 16 },
      gridIndex: 0
    },
    {
      type: 'category',
      data: transformedData.categories,
      inverse: true,
      show: false,
      gridIndex: 1
    }
  ],
  series: [
    {
      name: 'Shadow',
      type: 'custom',
      renderItem: function (params, api) {
        if (params.dataIndex === 0) return;
        var y0 = api.coord([0, params.dataIndex - 1])[1];
        var y1 = api.coord([0, params.dataIndex])[1];
        var barWidth = 36;
        var xPrev = api.coord([api.value(0, params.dataIndex - 1), 0])[0];
        var xCurr = api.coord([api.value(0, params.dataIndex), 0])[0];
        var xOrigin = api.coord([0, 0])[0];
        return {
          type: 'polygon',
          shape: {
            points: [
              [xOrigin, y0 + barWidth / 2],
              [xPrev, y0 + barWidth / 2],
              [xCurr, y1 - barWidth / 2],
              [xOrigin, y1 - barWidth / 2]
            ]
          },
          style: {
            fill: transformedData.colors[params.dataIndex - 1],
            opacity: 0.15
          }
        };
      },
      data: transformedData.barData.map(d => d.value),
      z: 1
    },
    {
      name: 'Connector',
      type: 'line',
      xAxisIndex: 1,
      yAxisIndex: 1,
      symbol: 'none',
      data: transformedData.circleData.map(d => [0.5, d.value[1]]),
      lineStyle: { color: '#e0e0e0', width: 4 },
      z: 2
    },
    {
      name: 'Value',
      type: 'bar',
      barWidth: 36,
      data: transformedData.barData,
      label: {
        show: true,
        position: 'right',
        formatter: function(p) { return p.value.toLocaleString() + '件'; },
        color: '#666',
        fontSize: 13,
        fontWeight: 'bold',
        offset: [5, 0]
      },
      itemStyle: { borderRadius: [0, 4, 4, 0] },
      z: 3
    },
    {
      name: 'Percentage',
      type: 'scatter',
      xAxisIndex: 1,
      yAxisIndex: 1,
      symbol: 'roundRect',
      symbolSize: [52, 28],
      data: transformedData.circleData.map((d, i) => ({
        value: [0.5, d.value[1]],
        pct: d.pct,
        itemStyle: { color: '#fff', borderColor: transformedData.colors[i], borderWidth: 2 }
      })),
      label: {
        show: true,
        position: 'inside',
        formatter: function (p) { return p.data.pct; },
        color: '#444',
        fontSize: 11,
        fontWeight: 'bold'
      },
      z: 4
    }
  ]
};
